        message = "BoundaryConditions.BodyLoads.CentrifugalForce.CoordinateSystems({},'{}',{},{},{},{},{},{},{})".format(crlTargetsCursor,strName,dVelocity,dAcceleration,iAxisDirection,iVelocityUnit,iAccelerationUnit,crCurCoordCursor,crEditCursor)
