        crEditCursor = "" if crEdit == None else crEdit.getPSJStr()
        message = "BoundaryConditions.EnforcedLoads.Acceleration('{}',{},{},{},{},{},{},{},{},{},{},{},{},{},{},{},{},{},{},{},{},{},{},{})".format(strName,dAccelUx,dAccelUy,dAccelUz,dAccelRx,dAccelRy,dAccelRz,crCurCoordCursor,iArrowDir,crTableCursor,dPhase,dDelay,crPhaseTableCursor,bExport,crMEExportUxCursor,crMEExportUyCursor,crMEExportUzCursor,crMEExportRxCursor,crMEExportRyCursor,crMEExportRzCursor,iAccelTransUnit,iAccelRotUnit,crlTargetsCursor,crEditCursor)
