class Calculation_FreqResp:
    MPFMCFCalculation = FreqResp_MPFMCFCalculation()

    def LoadCondition(self, crTargetAnalysis=None,crCoordinate=None,strName="FRQLOAD1",iLoadDirection=0,dlForce=[1, 0, 0],dAmplitude=1.0,dDelay=0.0,dPhase=0.0,bBf=False,dBf=1.0,crBfCurve=None,bFf=False,dFf=0.0,crFfCurve=None,bUnitLoad=False,bCentrifugalForce=False,crlTargets=[],crEdit=None):
        r"""
        ## Description
        
        Set the steady-state excitation input for frequency response.
        
        ## Syntax
        
        ```psj
        Calculation.FreqResp.LoadCondition(...)
        ```
        
        Macro: [DYNAMIC_FREQ_ANALYSIS_LOAD](../../macro/calculation/DYNAMIC_FREQ_ANALYSIS_LOAD)
        
        Ribbon: <menuselection>Calculation &#187; FreqResp &#187; LoadCondition</menuselection>
        
        ## Inputs
        
        ### `crTargetAnalysis`
        
        - A _Cursor_ specifying the target analysis. A new analysis is created if this parameter is set as None.
        - The default value is _None_.
        
        ### `crCoordinate`
        
        - A _Cursor_ specifying the output coordinate system.
        - The default value is _None_.
        
        ### `strName`
        
        - A _String_ specifying the name of load condition to be created.
        - The default value is "FRQLOAD1".
        
        ### `iLoadDirection`
        
        - An _Integer_ specifying the direction of vibration.
        - The default value is 0.
        
        ### `dlForce`
        
        - A _List of Double_ specifying the vector of vibration force.
        - The default value is [1,0,0].
        
        ### `dAmplitude`
        
        - A _Double_ specifying the amplitude of vibration force.
        - The default value is 1.0.
        
        ### `dDelay`
        
        - A _Double_ specifying the value of time delay (seconds).
        - The default value is 0.0.
        
        ### `dPhase`
        
        - A _Double_ specifying the value of phase delay (angle).
        - The default value is 0.0.
        
        ### `bBf`
        
        - A _Boolean_ specifying whether to use frequency-dependent load as Table input.
        - The default value is _False_.
        
        ### `dBf`
        
        - A _Double_ specifying the value of frequency-dependent load (Bf).
        - The default value is 1.0.
        
        ### `crBfCurve`
        
        - A _Cursor_ specifying the field data of frequency-dependent load.
        - The default value is _None_.
        
        ### `bFf`
        
        - A _Boolean_ specifying whether to use frequency-dependent phase as Table input.
        - The default value is _False_.
        
        ### `dFf`
        
        - A _Double_ specifying the value of Frequency-dependent phase.
        - The default value is 0.0.
        
        ### `crFfCurve`
        
        - A _Cursor_ specifying the field data of frequency-dependent phase.
        - The default value is _None_.
        
        ### `bUnitLoad`
        
        - A _Boolean_ specifying whether to create a load and load case under the condition that each selected node is subjected to unit vibration.
        - The default value is _False_.
        
        ### `bCentrifugalForce`
        
        - A _Boolean_ specifying whether to use the centrifugal force.
        - The default value is _False_.
        
        ### `crlTargets`
        
        - A _List of Cursor_ specifying the selected nodes which can be assigned the load condition.
        - This is a required input.
        
        ### `crEdit`
        
        - A _Cursor_ specifying an existing load condition
            - If this parameter is used, the specified load condition will be modified.
            - If it is left None, a new load condition will be created.
        - The default value is _None_.
        
        ## Return Code
        
        A _Cursor_ specifying the created frequency load condition.
        
        ## Sample Code
        
        ```psj {6-7}
        # Prepare result model
        samplePath = JPT.GetProgramPath() + "SampleData\\PSJ\\PSJ-Utility\\PostSample\\plate_eigen.op2"
        Home.ImportResults.Nastran(strPath = samplePath, dFaceAngle=60.16, dEdgeAngle=60.16)
        
        # Create a load condition
        loadCondition = Calculation.FreqResp.LoadCondition(strName="FRQLoad_1", iLoadDirection=2, dlForce=[0.0, 0.0, 10.0], 
                                                            dAmplitude=10.0, crlTargets=[Node(1516)])
        JPT.Debugger(loadCondition)
        ```
        
        """
        crTargetAnalysisCursor = "" if crTargetAnalysis == None else crTargetAnalysis.getPSJStr()
        crCoordinateCursor = "" if crCoordinate == None else crCoordinate.getPSJStr()
        crBfCurveCursor = "" if crBfCurve == None else crBfCurve.getPSJStr()
        crFfCurveCursor = "" if crFfCurve == None else crFfCurve.getPSJStr()
        crlTargetsCursor = f"[{', '.join(crl.getPSJStr() for crl in crlTargets)}]"
        crEditCursor = "" if crEdit == None else crEdit.getPSJStr()
        message = "Calculation.FreqResp.LoadCondition({},{},'{}',{},{},{},{},{},{},{},{},{},{},{},{},{},{},{})".format(crTargetAnalysisCursor,crCoordinateCursor,strName,iLoadDirection,dlForce,dAmplitude,dDelay,dPhase,bBf,dBf,crBfCurveCursor,bFf,dFf,crFfCurveCursor,bUnitLoad,bCentrifugalForce,crlTargetsCursor,crEditCursor)
        return JPT_RUN_LINE(message)

    def SaveAnalysis(self, strPath='',crlTargets=[],bBdfMode=False):
        r"""
        ## Description
        
        Save the results of a frequency response analysis (*.tsdv).
        
        ## Syntax
        
        ```psj
        Calculation.FreqResp.SaveAnalysis(...)
        ```
        
        Macro: [CmdSaveOpenTsdv](../../macro/calculation/CmdSaveOpenTsdv)
        
        Ribbon: <menuselection>Calculation &#187; FreqResp &#187; SaveAnalysis</menuselection>
        
        ## Inputs
        
        ### `strPath`
        
        - A _String_ specifying the path of file to be saved.
        - This is a required input.
        
        ### `crlTargets`
        
        - A _List of Cursor_ specifying the specified analysis targets to be saved.
        - This is a required input.
        
        ### `bBdfMode`
        
        - A _Boolean_ specifying whether to use the BDF mode.
        - The default value is _False_.
        
        ## Return Code
        
        - A _Boolean_ specifying whether the process is executed successfully or not:
            - _True_: The process is executed successfully.
            - _False_: Cannot execute the function.
        
        ## Sample Code
        
        ```psj {19}
        # Prepare result model
        samplePath = JPT.GetProgramPath() + "SampleData\\PSJ\\PSJ-Utility\\PostSample\\plate_eigen.op2"
        Home.ImportResults.Nastran(strPath = samplePath, dFaceAngle=60.16, dEdgeAngle=60.16)
        
        # Create a load condition
        Calculation.FreqResp.LoadCondition(strName="FRQLoad_1", iLoadDirection=2, dlForce=[0.0, 0.0, 10.0], 
                                            dAmplitude=10.0, crlTargets=[Node(1516)])
        
        # Create a load case
        Calculation.FreqResp.LoadCaseCondition(crTargetAnalysis=PostFreqAnalysis(1), strName="LoadCase_1", 
                                    crlSelectedLoad=[PostFreqLoad(1)], dlTargetFactor=[1.0])
        
        # Create a response condition
        Calculation.FreqResp.ResponseCondition(crTargetAnalysis=PostFreqAnalysis(1), dDampingFactor=0.02, 
                                                dStyleParamMid=10.0, dStyleParamBot=200.0, 
                                                strlResultNames=["TZ"], crlTargets=[Node(1516, 1016)])
        
        # Save analysis (Please set path to your temp folder.)
        Calculation.FreqResp.SaveAnalysis(strPath="C:/temp/TransRespAnalysis.tsdv", crlTargets=[PostFreqAnalysis(1)])
        ```
        
        """
        crlTargetsCursor = f"[{', '.join(crl.getPSJStr() for crl in crlTargets)}]"
        message = "Calculation.FreqResp.SaveAnalysis('{}',{},{})".format(strPath,crlTargetsCursor,bBdfMode)
        return JPT_RUN_LINE(message)

    def OpenAnalysis(self, strPath='',bBdfMode=False):
        r"""
        ## Description
        
        Load the results of a frequency response analysis (*.tsdv).
        
        ## Syntax
        
        ```psj
        Calculation.FreqResp.OpenAnalysis(...)
        ```
        
        Macro: [CmdSaveOpenTsdv](../../macro/calculation/CmdSaveOpenTsdv)
        
        Ribbon: <menuselection>Calculation &#187; FreqResp &#187; OpenAnalysis</menuselection>
        
        ## Inputs
        
        ### `strPath`
        
        - A _String_ specifying the path of file will be opened.
        - This is a required input.
        
        ### `bBdfMode`
        
        - A _Boolean_ specifying whether to use BDF mode.
        - The default value is _False_.
        
        ## Return Code
        
        - A _Boolean_ specifying whether the process is executed successfully or not:
            - _True_: The process is executed successfully.
            - _False_: Cannot execute the function.
        
        ## Sample Code
        
        ```psj {24}
        # Prepare result model
        samplePath = JPT.GetProgramPath() + "SampleData\\PSJ\\PSJ-Utility\\PostSample\\plate_eigen.op2"
        Home.ImportResults.Nastran(strPath = samplePath, dFaceAngle=60.16, dEdgeAngle=60.16)
        
        # Create a load condition
        Calculation.FreqResp.LoadCondition(strName="FRQLoad_1", iLoadDirection=2, dlForce=[0.0, 0.0, 10.0], 
                                            dAmplitude=10.0, crlTargets=[Node(1516)])
        
        # Create a load case
        Calculation.FreqResp.LoadCaseCondition(crTargetAnalysis=PostFreqAnalysis(1), strName="LoadCase_1", 
                                        crlSelectedLoad=[PostFreqLoad(1)], dlTargetFactor=[1.0])
        
        # Create a response condition
        Calculation.FreqResp.ResponseCondition(crTargetAnalysis=PostFreqAnalysis(1), dDampingFactor=0.02, 
                                                dStyleParamMid=10.0, dStyleParamBot=200.0, 
                                                strlResultNames=["TZ"], crlTargets=[Node(1516, 1016)])
        
        # Close current document and import the result file again
        JPT.CloseDocumentByName("plate_eigen")
        JPT.CreateNewDocument()
        Home.ImportResults.Nastran(strPath = samplePath, dFaceAngle=60.16, dEdgeAngle=60.16)
        
        # Open the saved analysis (Please set path to your temp folder and saved analysis file.)
        openFile = Calculation.FreqResp.OpenAnalysis(strPath="C:/temp/TransRespAnalysis.tsdv")
        JPT.Debugger(openFile)
        ```
        
        """

        message = "Calculation.FreqResp.OpenAnalysis('{}',{})".format(strPath,bBdfMode)
        return JPT_RUN_LINE(message)

    def LoadCaseCondition(self, crTargetAnalysis=None,strName="LoadCase1",dFactor=1.0,iNewID=1,crlSelectedLoad=[],dlTargetFactor=[],crEdit=None):
        r"""
        ## Description
        
        Set the steady-state excitation input for frequency response (Solver).
        
        ## Syntax
        
        ```psj
        Calculation.FreqResp.LoadCase(...)
        ```
        
        Macro: [DYNAMIC_FREQ_ANALYSIS_LOADCASE](../../macro/calculation/DYNAMIC_FREQ_ANALYSIS_LOADCASE)
        
        Ribbon: <menuselection>Calculation &#187; FreqResp &#187; LoadCase</menuselection>
        
        ## Inputs
        
        ### `crTargetAnalysis`
        
        - A _Cursor_ specifying the target analysis to be create a load case. A new analysis is created if this parameter is set as None.
        - The default value is _None_.
        
        ### `strName`
        
        - A _String_ specifying the name of load case to be created.
        - The default value is "LoadCase1".
        
        ### `dFactor`
        
        - A _Double_ specifying the load coefficient for the entire load cases to be created.
        - The default value is 1.0.
        
        ### `iNewID`
        
        - An _Integer_ specifying the ID of the load case to be created.
        - The default value is 1.
        
        ### `crlSelectedLoad`
        
        - A _List of Cursor_ specifying the selected loads will be used in the load case to be created.
        - The default value is [].
        
        ### `dlTargetFactor`
        
        - A _List of Double_ specifying the coefficient for each selected load in the corresponding order.
        - The default value is [].
        
        ### `crEdit`
        
        - A _Cursor_ specifying an existing load case condition
            - If this parameter is used, the specified load case condition will be modified.
            - If it is left None, a new load case condition will be created.
        - The default value is _None_.
        
        ## Return Code
        
        A _Cursor_ specifying the created frequency load case.
        
        ## Sample Code
        
        ```psj {9-10}
        # Prepare result model
        samplePath = JPT.GetProgramPath() + "SampleData\\PSJ\\PSJ-Utility\\PostSample\\plate_eigen.op2"
        Home.ImportResults.Nastran(strPath = samplePath, dFaceAngle=60.16, dEdgeAngle=60.16)
        # Create a load condition
        Calculation.FreqResp.LoadCondition(strName="FRQLoad_1", iLoadDirection=2, dlForce=[0.0, 0.0, 10.0], 
                                            dAmplitude=10.0, crlTargets=[Node(1516)])
        
        # Create a load case
        loadCase = Calculation.FreqResp.LoadCaseCondition(crTargetAnalysis=PostFreqAnalysis(1), strName="LoadCase_1", 
                                                    crlSelectedLoad=[PostFreqLoad(1)], dlTargetFactor=[1.0])
        JPT.Debugger(loadCase)
        ```
        
        """
        crTargetAnalysisCursor = "" if crTargetAnalysis == None else crTargetAnalysis.getPSJStr()
        crlSelectedLoadCursor = f"[{', '.join(crl.getPSJStr() for crl in crlSelectedLoad)}]"
        crEditCursor = "" if crEdit == None else crEdit.getPSJStr()
        message = "Calculation.FreqResp.LoadCaseCondition({},'{}',{},{},{},{},{})".format(crTargetAnalysisCursor,strName,dFactor,iNewID,crlSelectedLoadCursor,dlTargetFactor,crEditCursor)
        return JPT_RUN_LINE(message)

    def ResponseCondition(self, crTargetAnalysis=None,crCoordinate=None,bAllModesUsed=True,strlModesSelected=[],bDampingFactor=True,dDampingFactor=0.01,crDampingFactor=None,iCurveStyle=1,dStyleParamTop=0.0,dStyleParamMid=1.0,dStyleParamBot=1.0,bIncludeEigenValue=False,bCreateNewResult=False,iResultType=0,strlResultNames=["TX"],iResultPosition=0,bAllLoadCases=True,crSelectedLoadCase=None,bSeparateLoad=False,crlTargets=[],crEdit=None):
        r"""
        ## Description
        
        Output the result of the response point for frequency response.
        
        ## Syntax
        
        ```psj
        Calculation.FreqResp.ResponseCondition(...)
        ```
        
        Macro: [ResponseCondition](../../macro/calculation/ResponseCondition)
        
        Ribbon: <menuselection>Calculation &#187; FreqResp &#187; ResponseCondition</menuselection>
        
        ## Inputs
        
        ### `crTargetAnalysis`
        
        - A _Cursor_ specifying the target job to be processed.
        - The default value is _None_.
        
        ### `crCoordinate`
        
        - A _Cursor_ specifying the output coordinate system.
        - The default value is _None_.
        
        ### `bAllModesUsed`
        
        - A _Boolean_ specifying whether to use all modes.
        - The default value is _True_.
        
        ### `strlModesSelected`
        
        - A _List of String_ specifying the selected modes using for response calculation. This option was used if bAllModesUsed is _False_.
        - The default value is [].
        
        ### `bDampingFactor`
        
        - A _Boolean_ specifying whether to use damping factor for calculation. 
        - The default value is _True_.
        
        ### `dDampingFactor`
        
        - A _Double_ specifying the value of damping factor.
        - The default value is 0.01.
        
        ### `crDampingFactor`
        
        - A _Cursor_ specifying the field data of damping factor.
        - The default value is _None_.
        
        ### `iCurveStyle`
        
        - An _Integer_ specifying the style of time range for the calculation.
            - 0: Start + StepNumber + StepSize
            - 1: Start + StepSize + End
            - 2: Start + StepNumber + End
        - The default value is 1.
        
        ### `dStyleParamTop`
        
        - A _Double_ specifying the analysis start value of the selected curve style.
        - The default value is 0.0.
        
        ### `dStyleParamMid`
        
        - A _Double_ specifying the step size value of the selected curve style.
        - The default value is 1.0.
        
        ### `dStyleParamBot`
        
        - A _Double_ specifying the analysis end value of the selected curve style.
        - The default value is 1.0.
        
        ### `bIncludeEigenValue`
        
        - A _Boolean_ specifying whether to plot the frequency of eigen value.
        - The default value is _False_.
        
        ### `bCreateNewResult`
        
        - A _Boolean_ specifying whether to create new results (displacement and stress) for the entire model.
        - The default value is _False_.
        
        ### `iResultType`
        
        - An _Integer_ specifying the result type to be calculated.
            - 0: Displacement
            - 1: Velocity
            - 2: Acceleration
            - 3: Stress (Solid)
            - 4: Stress (Shell)
            - 5: Disp. + Stress. This result type was displayed when bCreateNewResult = _True_.
        - The default value is 0.
        
        ### `strlResultNames`
        
        - A _List of String_ specifying the component results according to the selected result type.
        - The default value is ["TX"].
        
        ### `iResultPosition`
        
        - An _Integer_ specifying the output position of the result.
        - The default value is 0.
        
        ### `bAllLoadCases`
        
        - A _Boolean_ specifying whether to use all current load cases.
        - The default value is _True_.
        
        ### `crSelectedLoadCase`
        
        - A _Cursor_ specifying the selected load case to analyze. This option was used if bAllLoadCases is _False_.
        - The default value is _None_.
        
        ### `bSeparateLoad`
        
        - A _Boolean_ specifying whether to calculate the response to each set load.
        - The default value is _False_.
        
        ### `crlTargets`
        
        - A _List of Cursor_ specifying the target to calculate the response. The target is node or solid element.
        - This is a required input.
        
        ### `crEdit`
        
        - A _Cursor_ specifying an existing response condition
            - If this parameter is used, the specified response condition will be modified.
            - If it is left None, a new response condition will be created.
        - The default value is _None_.
        
        ## Return Code
        
        A _Cursor_ specifying the created frequency response condition.
        
        ## Sample Code
        
        ```psj {14-17}
        # Prepare result model
        samplePath = JPT.GetProgramPath() + "SampleData\\PSJ\\PSJ-Utility\\PostSample\\plate_eigen.op2"
        Home.ImportResults.Nastran(strPath = samplePath, dFaceAngle=60.16, dEdgeAngle=60.16) 
        
        # Create a load condition
        Calculation.FreqResp.LoadCondition(strName="FRQLoad_1", iLoadDirection=2, dlForce=[0.0, 0.0, 10.0], 
                                            dAmplitude=10.0, crlTargets=[Node(1516)]) 
        
        # Create a load case
        Calculation.FreqResp.LoadCaseCondition(crTargetAnalysis=PostFreqAnalysis(1), strName="LoadCase_1", 
                                        crlSelectedLoad=[PostFreqLoad(1)], dlTargetFactor=[1.0])
        
        # Create a response condition
        respCondition = Calculation.FreqResp.ResponseCondition(crTargetAnalysis=PostFreqAnalysis(1), 
                                                                dDampingFactor=0.02, dStyleParamMid=10.0, 
                                                                dStyleParamBot=200.0, strlResultNames=["TZ"], 
                                                                crlTargets=[Node(1516, 1016)])
        Chart.CreateGraph(crTargetCurve=PostFreqResultCurve(1), strChartTitle="Frequency Analysis Displacement", 
                        strAxisTitleX="Frequency", strAxisTitleY="Amplitude", bNewChart=False)
        Chart.CreateGraph(crTargetCurve=PostFreqResultCurve(3), strChartTitle="Frequency Analysis Displacement", 
                        strAxisTitleX="Frequency", strAxisTitleY="Amplitude", bNewChart=False)
        JPT.Debugger(respCondition) # for checking the return value
        ```
        
        """
        crTargetAnalysisCursor = "" if crTargetAnalysis == None else crTargetAnalysis.getPSJStr()
        crCoordinateCursor = "" if crCoordinate == None else crCoordinate.getPSJStr()
        crDampingFactorCursor = "" if crDampingFactor == None else crDampingFactor.getPSJStr()
        crSelectedLoadCaseCursor = "" if crSelectedLoadCase == None else crSelectedLoadCase.getPSJStr()
        crlTargetsCursor = f"[{', '.join(crl.getPSJStr() for crl in crlTargets)}]"
        crEditCursor = "" if crEdit == None else crEdit.getPSJStr()
        message = "Calculation.FreqResp.ResponseCondition({},{},{},'{}',{},{},{},{},{},{},{},{},{},{},'{}',{},{},{},{},{},{})".format(crTargetAnalysisCursor,crCoordinateCursor,bAllModesUsed,strlModesSelected,bDampingFactor,dDampingFactor,crDampingFactorCursor,iCurveStyle,dStyleParamTop,dStyleParamMid,dStyleParamBot,bIncludeEigenValue,bCreateNewResult,iResultType,strlResultNames,iResultPosition,bAllLoadCases,crSelectedLoadCaseCursor,bSeparateLoad,crlTargetsCursor,crEditCursor)
        return JPT_RUN_LINE(message)

