class MeshCleanup_Cleanup:
    def CloseGap(self, crlPartCur,dDistanceTol):
        r"""
        To be updated
        """
        crlPartCurCursor = f"[{', '.join(crl.getPSJStr() for crl in crlPartCur)}]"
        message = "MeshCleanup.Cleanup.CloseGap({},{})".format(crlPartCurCursor,dDistanceTol)
        return JPT_RUN_LINE(message)

    def Manual(self, crlParts=[],iElemType=0,iVeQuality=0,iCheckCondition=0,dLimitValue=0.0,dCFLValue=0.0,iNonManifold=0,iCleanupMode=0,crlElems=[]):
        r"""
        ## Description
        
        Command for cleaning surface mesh elements that do not meet the specified quality criteria.
        
        ## Syntax
        
        ```psj
        MeshCleanup.Cleanup.Manual(...)
        ```
        
        Macro: [CleanupManual](../../macro/mesh-cleanup/CleanupManual)
        
        Ribbon: <menuselection>MeshCleanup &#187; Auto Check &#187; Cleanup</menuselection>
        
        ## Inputs
        
        ### `crlParts`
        - A _List of Cursor_ of parts to be cleaned up.
        - Default value is [].
        
        ### `iElemType`
        - An _Integer_ specifying the type of target elements.
          - 0: Tri
          - 1: Quad
        - Default value is 0.
        
        ### `iVeQuality`
        - An _Integer_ specifying the quality metric.
          - 0: Stretch
          - 1: Aspect Ratio
          - 2: Edge Length
          - 3: Area
          - 4: Warp
          - 5: Skew
          - 6: VDS Stretch
          - 7: Node Valence
          - 8: Volume
          - 9: Interior Angle
          - 10: Jacobian
          - 11: Taper
          - 12: Node Free Edges
          - 13: Duplicate Elements
          - 14: Tet Collapse
          - 15: Tet Skew
          - 16: Tet Collapse 2
          - 17: Vol Aspect Ratio
          - 18: Unstable
          - 19: CFL Condition
        - Default value is 0.
        
        ### `iCheckCondition`
        - An _Integer_ specifying the check condition.
          - 0: &lt;=
          - 1: &gt;=
          - 2: &lt;
          - 3: &gt;
        - Default value is 0.
        
        ### `dLimitValue`
        - A _Double_ specifying the quality threshold.
        - Default value is 0.0.
        
        ### `dCFLValue`
        - A _Double_ specifying the CFL threshold value.
        - Default value is 0.0.
        
        ### `iNonManifold`
        - An _Integer_ specifying whether to include non-manifold elements.
          - 0: Exclude
          - 1: Include
        - Default value is 0.
        
        ### `iCleanupMode`
        - An _Integer_ specifying the cleanup mode.
          - 0: Standard
          - 1: Aggressive
        - Default value is 0.
        
        ### `crlElems`
        - A _List of Cursor_ specifying the target elements.
        - Default value is [].
        
        ## Return Code
        
        Returns a string "1" if successful, or "0" if failed.
        
        ## Sample Code
        
        ```psj{20-25}
        # Prepare Model
        Geometry.Part.Cube(ilAxialNodes=[3, 3, 3], iPartColor=7463537)
        MeshEdit.CreateNode.Point(
          iNewNodeID=27,
          posPoint=[
            0.005225089844316244,
            0.00481416005641222,
            0.009999999776482582,
          ],
          crTarget=Face(26),
        )
        
        # Check
        ret = MeshCleanup.ManualCheck.Tri(
          crlTargets=[Part(1)],
          iCheckCondition=0,
          dLimitValue=0.1,
        )
        print(f"number of error elements: {ret[5]}")
        MeshCleanup.Cleanup.Manual(
          crlParts=[Part(1)],
          dLimitValue=0.1,
          dCFLValue=0.1,
          crlElems=ret[6],
        )
        
        ret = MeshCleanup.ManualCheck.Tri(
          crlTargets=[Part(1)],
          iCheckCondition=0,
          dLimitValue=0.1,
        )
        print(f"number of error elements: {ret[5]}")
        ```
        
        """
        crlPartsCursor = f"[{', '.join(crl.getPSJStr() for crl in crlParts)}]"
        crlElemsCursor = f"[{', '.join(crl.getPSJStr() for crl in crlElems)}]"
        message = "MeshCleanup.Cleanup.Manual({},{},{},{},{},{},{},{},{})".format(crlPartsCursor,iElemType,iVeQuality,iCheckCondition,dLimitValue,dCFLValue,iNonManifold,iCleanupMode,crlElemsCursor)
        return JPT_RUN_LINE(message)

    def Auto(self, crlParts,iElemType,blCheckCondition,blElemQuality,dlLimitValue,crlElems):
        r"""
        ## Description
        
        Command for automatically cleaning triangle or quadrilateral mesh elements based on quality check results.
        
        ## Syntax
        
        ```psj
        MeshCleanup.Cleanup.Auto(...)
        ```
        
        Macro: [CleanupAuto](../../macro/mesh-cleanup/CleanupAuto)
        
        ## Inputs
        
        ### `crlParts`
        - A _List of Cursor_ specifying the target parts.
        - This is a required input.
        
        ### `iElemType`
        - An _Integer_ specifying the type of target elements.
          - 0: Triangle
          - 1: Quadrilateral
        - This is a required input.
        
        ### `blCheckCondition`
        - A _List of Boolean_ specifying the condition check enable flags for each cleanup condition.
        - This is a required input.
        
        ### `blElemQuality`
        - A _List of Boolean_ specifying the enable flags for each element quality metric.
        - This is a required input.
        
        ### `dlLimitValue`
        - A _List of Double_ specifying the threshold value for each quality metric.
        - This is a required input.
        
        ### `crlElems`
        - A _List of Cursor_ specifying the target elements.
        - This is a required input.
        
        ## Return Code
        
        Returns a string "1" if successful, or "0" if failed.
        
        ## Sample Code
        
        ```psj {38-45}
        #Prepare Model
        Geometry.Part.Cube(
            ilAxialNodes=[3, 3, 3], 
            iPartColor=7463537
        )
        
        MeshCleanup.Manual2D.Split(
            crplElemEdge=[CursorPair(Node(7), Node(15))], 
            dRatio=0.99
        )
        
        MeshCleanup.Manual2D.Split(
            crplElemEdge=[CursorPair(Node(16), Node(22))], 
            dRatio=0.99
        )
        
        # Check
        result = MeshCleanup.AutoCheck.Tri(
            crlTargets=[Part(1)], 
            bStretchCheck=True, 
            bAspectRatioCheck=True, 
            bEdgeLengthCheck=True, 
            bAreaCheck=True, 
            bNodeValenceCheck=True, 
            bInteriorAngleCheck=True, 
            bDuplicateElemsCheck=True, 
            dStretchLimit=0.1, 
            dAspectRatioLimit=10, 
            dEdgeLengthLimit=0.0001, 
            dAreaLimit=1e-08, 
            dNodeValenceLimit=10, 
            dInteriorAngleLimit=0.174533
        )
        
        print(f"Number of error elements: {result[1]}")
        
        # Auto cleanup
        MeshCleanup.Cleanup.Auto(
            crlParts=[Part(1)], 
            iElemType=0, 
            blCheckCondition=[False, True, False, False, True, False, False], 
            blElemQuality=[False, True, True, True, True, True, True],
             dlLimitValue=[0.1, 10.0, 0.0001, 1e-08, 10.0, 10.0, 0.0], 
            crlElems=result[2]
        )
        
        result = MeshCleanup.AutoCheck.Tri(
            crlTargets=[Part(1)], 
            bStretchCheck=True, 
            bAspectRatioCheck=True, 
            bEdgeLengthCheck=True, 
            bAreaCheck=True, 
            bNodeValenceCheck=True, 
            bInteriorAngleCheck=True, 
            bDuplicateElemsCheck=True, 
            dStretchLimit=0.1, 
            dAspectRatioLimit=10, 
            dEdgeLengthLimit=0.0001, 
            dAreaLimit=1e-08, 
            dNodeValenceLimit=10, 
            dInteriorAngleLimit=0.174533
        )
        
        print(f"Number of error elements: {result[1]}")
        ```
        
        """
        crlPartsCursor = f"[{', '.join(crl.getPSJStr() for crl in crlParts)}]"
        crlElemsCursor = f"[{', '.join(crl.getPSJStr() for crl in crlElems)}]"
        message = "MeshCleanup.Cleanup.Auto({},{},{},{},{},{})".format(crlPartsCursor,iElemType,blCheckCondition,blElemQuality,dlLimitValue,crlElemsCursor)
        return JPT_RUN_LINE(message)

