class Post_Note:
    def Node(self, crlTargets=[]):
        r"""
        ## Description
        
        Add a note indication to the selected node on the main window, and input it to the data table in the Node tab of the Watch Data window.
        
        ## Syntax
        
        ```psj
        Post.Note.Node(...)
        ```
        
        Macro: [CmdMarkupNode](../../macro/post/CmdMarkupNode)
        
        Ribbon: <menuselection>Post &#187; Note &#187; Node</menuselection>
        
        ## Inputs
        
        ### `crlTargets`
        
        - A _List of Cursor_ specifying the selected nodes to markup the notes.
        - This is a required input.
        
        ## Return Code
        
        - A _Boolean_ specifying whether the process is executed successfully or not.
            - _True_: The process is executed successfully.
            - _False_: Cannot execute the function.
        
        ## Sample Code
        
        ```psj {25}
        # Prepare Post model
        samplePath = JPT.GetProgramPath() + "SampleData\\PSJ\\PSJ-Utility\\PostSample\\103_solid.op2"
        Home.ImportResults.Nastran(strPath = samplePath, dFaceAngle=60.16, dEdgeAngle=60.16)
        # Plot the result
        Post.ShowContour(crPostJob=TSVPostJob(1), 
                        lContourSettings=[PostContourSetting(postResultKey=PostResultKey(
                        iAnalysisType=2, 
                        iResultSet=1, 
                        iTimeStep=1, 
                        strResultName="Displacement", 
                        strResultCompName="Translational", 
                        iResultPos=1), 
                        postDataOp=PostDataOp(
                        iResultLocation=1, 
                        iOptionCoord=4))])
        Post.ShowDeformation(crPostJob=TSVPostJob(1), 
                            postResultKey=PostResultKey(
                            iAnalysisType=2, 
                            iResultSet=1, 
                            iTimeStep=1, 
                            strResultName="Displacement", 
                            strResultCompName="Translational"))
        
        # Display note at the selected nodes
        Post.Note.Node(crlTargets=[RONode(129,133)])
        ```
        
        """
        crlTargetsCursor = f"[{', '.join(crl.getPSJStr() for crl in crlTargets)}]"
        message = "Post.Note.Node({})".format(crlTargetsCursor)
        return JPT_RUN_LINE(message)

    def NodeSearchFromPoints(self, dlPositions=[]):
        r"""
        ## Description
        
        Search the nearest node from the specified point and markup its node note
        
        ## Syntax
        
        ```psj
        Post.Note.NodeSearchFromPoints(...)
        ```
        
        Macro: [CmdMarkupSearchNodeFromPoint](../../macro/post/CmdMarkupSearchNodeFromPoint),
               [CmdMarkupSearchNodesFromMultiPoints](../../macro/post/CmdMarkupSearchNodesFromMultiPoints),
        
        Ribbon: <menuselection>Post &#187; Note &#187; NodeSearchFromPoints</menuselection>
        
        ## Inputs
        
        ### `dlPositions`
        
        - A _List of Double_ specifying the coordinates of points to search the nearest nodes.
        - This is a required input.
        
        ## Return Code
        
        - A _Boolean_ specifying whether the process is executed successfully or not.
            - _True_: The process is executed successfully.
            - _False_: Cannot execute the function.
        
        ## Sample Code
        
        ```psj {25}
        # Prepare Post model
        samplePath = JPT.GetProgramPath() + "SampleData\\PSJ\\PSJ-Utility\\PostSample\\103_solid.op2"
        Home.ImportResults.Nastran(strPath = samplePath, dFaceAngle=60.16, dEdgeAngle=60.16)
        # Plot the result
        Post.ShowContour(crPostJob=TSVPostJob(1), 
                        lContourSettings=[PostContourSetting(postResultKey=PostResultKey(
                        iAnalysisType=2, 
                        iResultSet=1, 
                        iTimeStep=1, 
                        strResultName="Displacement", 
                        strResultCompName="Translational", 
                        iResultPos=1), 
                        postDataOp=PostDataOp(
                        iResultLocation=1, 
                        iOptionCoord=4))])
        Post.ShowDeformation(crPostJob=TSVPostJob(1), 
                            postResultKey=PostResultKey(
                            iAnalysisType=2, 
                            iResultSet=1, 
                            iTimeStep=1, 
                            strResultName="Displacement", 
                            strResultCompName="Translational"))
                            
        # Search nodes from points and markup notes
        node = Post.Note.NodeSearchFromPoints(dlPositions=[[30.0, 3.0, 2.5], [28.0, 8.0, 4.0]])
        if len(node) >=1:
            for i in range(len(node)):
                print("The searched node is:", str(node[i]))
        else:
            print("Cannot search the node from point")
        ```
        
        """

        message = "Post.Note.NodeSearchFromPoints({})".format(dlPositions)
        return JPT_RUN_LINE(message)

