class Measure_Distance:
    def TwoNodes(self, crNode1,crNode2,strTarget="ALL",iPrecision=6,crCoord=None):
        r"""
        ## Description
        
        Measure distance between two nodes.
        
        ## Syntax
        
        ```psj
        Tools.Measure.Distance.TwoNodes(...)
        ```
        
        Ribbon: <menuselection>Tools &#187; Measure &#187; Distance &#187; TwoNodes</menuselection>
        
        ## Inputs
        
        ### `crNode1`
        
        - A _Cursor_ specifying the first node to measure distance.
        - This is a required input.
        
        ### `crNode2`
        
        - A _Cursor_ specifying the second node to measure distance.
        - This is a required input.
        
        ### `strTarget`
        
        - A _String_ specifying the target projection axis, or the three-dimensional space (3D) to refer to measure. This parameter can be one of the following:
          - If _strTarget="X"_: Return the distance value along the X axis.
          - If _strTarget="Y"_: Return the distance value along the Y axis.
          - If _strTarget="Z"_: Return the distance value along the Z axis.
          - If _strTarget="Dist"_: Return the distance value on in 3D space.
          - If _strTarget="ALL"_: Return all the 4 distance values in a list, in order "Dist", "X", "Y", "Z".
        - The default value is "ALL".
        
        ### `iPrecision`
        
        - An _Integer_ specifying the number of digit after floating point. The greater `iPrecision` could be, the more accuracy of distance can be measured.
        - The default value is 6.
        
        ### `crCoord`
        
        - A _Cursor_ specifying the coordinate reference system in which the distance will refer to measure.
        - The default value is _None_.
        
        ## Return Code
        
        A _List of String_ specifying the distance between two nodes.
        
        ## Sample Code
        
        ```psj {3,4,5,6}
        Geometry.Part.Cube()
        
        distance = Tools.Measure.Distance.TwoNodes(crNode1=Node(454), 
                                                   crNode2=Node(472), 
                                                   strTarget="Dist")
        
        JPT.Debugger(distance)
        
        print_str = ", ".join([str(value) for value in distance])
        print(print_str)
        ```
        
        """
        crNode1Cursor = "" if crNode1 == None else crNode1.getPSJStr()
        crNode2Cursor = "" if crNode2 == None else crNode2.getPSJStr()
        crCoordCursor = "" if crCoord == None else crCoord.getPSJStr()
        message = "Tools.Measure.Distance.TwoNodes({},{},'{}',{},{})".format(crNode1Cursor,crNode2Cursor,strTarget,iPrecision,crCoordCursor)
        return JPT_RUN_LINE(message)

    def TwoPoints(self, posPoint1=[0, 0, 0],posPoint2=[0, 0, 0],strTarget="ALL",iPrecision=6,crCoordinateSystem=None):
        r"""
        ## Description
        
        Measure distance between two points
        
        ## Syntax
        
        ```psj
        Tools.Measure.Distance.TwoPoints(...)
        ```
        
        Ribbon: <menuselection>Tools &#187; Measure &#187; Distance &#187; TwoPoints</menuselection>
        
        ## Inputs
        
        ### `posPoint1`
        
        - A _Position_ specifying the point1.
        - The default value is [0,0,0].
        
        ### `posPoint2`
        
        - A _Position_ specifying the point2.
        - The default value is [0,0,0].
        
        ### `strTarget`
        
        - A _String_ specifying the target.
          - "Dist": Gets the measured distance.
          - "X": Gets the distance in the X direction.
          - "Y": Gets the distance in the Y direction.
          - "Z": Gets the distance in the Z direction.
          - "ALL": Gets all values of Dist, X, Y, Z as a list.
        - The default value is "ALL".
        
        ### `iPrecision`
        
        - An _Integer_ specifying the precision.
        - The default value is 6.
        
        ### `crCoordinateSystem`
        
        - A _Cursor_ specifying the coordinate system.
        - The default value is None.
        
        ## Return Code
        
        A _List of String_ specifying the distance between two points.
        
        ## Sample Code
        
        ```psj
        Geometry.Part.Cube(iPartColor=6409934)
        Tools.Measure.Distance.TwoPoints(
                posPoint1=[0.0077, 0.0011, 0.01], 
                posPoint2=[0.0075, 0.01, 0.0057])
        ```
        
        """
        crCoordinateSystemCursor = "" if crCoordinateSystem == None else crCoordinateSystem.getPSJStr()
        message = "Tools.Measure.Distance.TwoPoints({},{},'{}',{},{})".format(posPoint1,posPoint2,strTarget,iPrecision,crCoordinateSystemCursor)
        return JPT_RUN_LINE(message)

