class Exchange:
    def ReplaceSolidMesh(crlSourceFace,crlTargetFace,dTolerance):
        r"""
        ## Description
        
        Replace an adjacent solid part.
        
        ## Syntax
        
        ```psj
        Exchange.ReplaceSolidMesh(...)
        ```
        
        Macro: 
        
        Ribbon: <menuselection>Exchange &#187; ReplaceSolidMesh</menuselection>
        
        ## Inputs
        
        ### `crlSourceFace`
        
        - A _List of Cursor_ specifying source face (base model side).
        - This is a required input.
        
        ### `crlTargetFace`
        
        - A _List of Cursor_ specifying target face (echange part side).
        - This is a required input.
        
        ### `dTolerance`
        
        - A _Double_ specifying tolerance between source face and target face.
        - This is a required input.
        
        ## Return Code
        
        A _Boolean_ specifying the function successfully executed or not.
        
        ## Sample Code
        
        ```psj {19-22}
        Geometry.Part.Cube(iPartColor=6409934)
        Geometry.Part.Cube(
            dlOrigin=[0.01, 0.0, 0.0],
            ilAxialNodes=[4, 4, 4],
            strName="Cube_3",
            iPartColor=12867524)
        
        Meshing.SolidMeshing(crlParts=[Part(1,2)],
            bTet10=True,
            dGradingFactor=1.05,
            dStretchLimit=0.1,
            iSpeedVsQual=1,
            iRegion=1,
            bSafeMode=False,
            iParallel=16,
            bInternalMeshOnly=False,
            iPartColor=65280)
        
        ret=Exchange.ReplaceSolidMesh(
            crlSourceFace=[Face(24)],
            crlTargetFace=[Face(49)],
            dTolerance=0.0005)
        print(ret)
        ```
        
        """
        crlSourceFaceCursor = f"[{', '.join(crl.getPSJStr() for crl in crlSourceFace)}]"
        crlTargetFaceCursor = f"[{', '.join(crl.getPSJStr() for crl in crlTargetFace)}]"
        message = "Exchange.ReplaceSolidMesh({},{},{})".format(crlSourceFaceCursor,crlTargetFaceCursor,dTolerance)
        return JPT_RUN_LINE(message)

    def ClayWork(iProcess=0,iWrappingType=0,dlSphereCenter=[],dSphereRadius=0.0,crTargetPart=None,dFactor=0.0):
        r"""
        ## Description
        
        Make a simple design change for solid mesh parts.
        
        ## Syntax
        
        ```psj
        Exchange.ClayWork(...)
        ```
        
        Macro: 
        
        Ribbon: <menuselection>Exchange &#187; ClayWork</menuselection>
        
        ## Inputs
        
        ### `iProcess`
        
        - An _Integer_ specifying the process type.
        	- 0: Sphere
        	- 1: Boolean +
        	- 2: Boonlean -
        - The default value is 0.
        
        ### `iWrappingType`
        
        - An _Integer_ specifying the wrapping type. This argument only was used when `iProcess` = 1 or 2.
        	- 0: Tight
        	- 1: Convex
        - The default value is 0.
        
        ### `dlSphereCenter`
        
        - A _List of Double_ specifying the center coordinates of sphere.
        - The default value is [].
        
        ### `dSphereRadius`
        
        - A _Double_ specifying the radius of sphere.
        - The default value is 0.0.
        
        ### `crTargetPart`
        
        - A _Cursor_ specifying the part to which the wrapped sphere will be added or scraped off. This argument only was used when `iProcess` = 1 or 2.
        - The default value is _None_.
        
        ## Return Code
        
        A _Boolean_ specifying the function successfully executed or not.
        
        ## Sample Code
        
        ```psj {15-21,25}
        # Prepare model
        Geometry.Part.Cube(iPartColor=6409934)
        Meshing.SolidMeshing(
        	crlParts=[Part(1)], 
        	dGradingFactor=1.05, 
        	dStretchLimit=0.1, 
        	iSpeedVsQual=1, 
        	iRegion=1, 
        	bSafeMode=False, 
        	iParallel=16, 
        	bInternalMeshOnly=False, 
        	iPartColor=65280)
        
        # Add spheres
        ret1 = Exchange.ClayWork(
        		iProcesstype=0, 
        		dlSphereCenter=[
        			[0.006, 0.01, 0.002], [0.006, 0.01, 0.003], [0.006, 0.01, 0.004], [0.006, 0.01, 0.006], 
        			[0.006, 0.01, 0.007], [0.004, 0.01, 0.007], [0.004, 0.01, 0.006], [0.004, 0.01, 0.004], 
        			[0.004, 0.01, 0.003], [0.004, 0.01, 0.002]], 
        		dSphereRadius=0.002)
        print(ret1)
        
        # Pile up the wrapped sphere
        ret2 = Exchange.ClayWork(iProcesstype=1, iWrappingType=1, iFactor = 0.6, crTargetPart=Part(1))
        print(ret2)
        ```
        
        """
        crTargetPartCursor = "" if crTargetPart == None else crTargetPart.getPSJStr()
        message = "Exchange.ClayWork({},{},{},{},{},{})".format(iProcess,iWrappingType,dlSphereCenter,dSphereRadius,crTargetPartCursor,dFactor)
        return JPT_RUN_LINE(message)

    def AssembleSolidMesh(crNewPart=None,crlAssembleParts=[],crlNewFaces=[],crlAssembleFaces=[],dTolerance=0.0,iConnectPosition = 0,iRemeshLayer=2,bRemeshAuto=True,dAvg=0.0,dMin=0.0,dMax=0.0):
        r"""
        ## Description
        
        Assemble solid mesh parts.
        
        ## Syntax
        
        ```psj
        Exchange.AssembleSolidMesh(...)
        ```
        
        Macro: 
        
        Ribbon: <menuselection>Exchange &#187; AssembleSolidMesh</menuselection>
        
        ## Inputs
        
        ### `crNewPart`
        
        - A _Cursor_ specifying the new assembly part.
        - The default value is _None_.
        
        ### `crlAssembleParts`
        
        - A _List of Cursor_ specifying the original assembly part.
        - The default value is [].
        
        ### `crlNewFaces`
        
        - A _List of Cursor_ specifying the face to be shared on the new assembly part.
        - The default value is [].
        
        ### `crlAssembleFaces`
        
        - A _List of Cursor_ specifying the face to be shared on the original assembly part.
        - The default value is [].
        
        ### `dTolerance`
        
        - A _Double_ specifying the tolerance value.
        - The default value is 0.0.
        
        ### `iConnectPosition`
        
        - An _Integer_ specifying the position to create the shared face.
          - 0: Mid
          - 1: Mater
        - The default value is 0.
        
        ### `iRemeshLayer`
        
        - An _Integer_ specifying the number of layers to be remeshed around the new shared face.
        - The default value is 2.
        
        ### `bRemeshAuto`
        
        - A _Boolean_ specifying whether to set the mesh size automatically.
        - The default value is _True_.
        
        ### `dAvg`
        
        - A _Double_ specifying the average mesh size.
        - The default value is 0.0.
        
        ### `dMin`
        
        - A _Double_ specifying the minimum mesh size.
        - The default value is 0.0.
        
        ### `dMax`
        
        - A _Double_ specifying the maximum mesh size.
        - The default value is 0.0.
        
        ## Return Code
        
        A _Boolean_ specifying the function successfully executed or not.
        
        ## Sample Code
        
        ```psj {34,35}
        # Prepare model
        Geometry.Part.Cube(iPartColor=6409934)
        Geometry.Part.Cube(dlOrigin=[0.0101, 0.0, 0.0], strName="Cube_2", iPartColor=14903267)
        Meshing.AdjustCircleVertex(crlParts=[Part(2)], bInModeSurfaceMesh=True)
        Meshing.SetMeshAttribute(
            crlParts=[Part(2)], 
            surfaceMesh=SURFACE_MESH(
                dAvgElemSize=0.0015,
                 dGeomAngle=0.7853981634, 
                 iPerformanceMode=1, 
                 dAutoMergeTinyFacesAngle=0.5235987756, 
                 bGeomApprox=True))
        Meshing.SurfaceMeshing(
            crlParts=[Part(2)], 
            surfaceMesh=SURFACE_MESH(
                dAvgElemSize=0.0015, 
                dGeomAngle=0.7853981634, 
                iPerformanceMode=1, 
                dAutoMergeTinyFacesAngle=0.5235987756, 
                bGeomApprox=True), 
            iThreadNum=16)
        Meshing.SolidMeshing(
            rlParts=[Part(2, 1)], 
            dGradingFactor=1.05, 
            dStretchLimit=0.1, 
            iSpeedVsQual=1, 
            iRegion=1, 
            bSafeMode=False, 
            iParallel=16, 
            bInternalMeshOnly=False, 
            iPartColor=65280)
        
        # Assemble solid mesh
        ret = Exchange.AssembleSolidMesh(crNewPart=Part(2), crlAssembleParts=[Part(1)], dTolerance=0.0002, 
            iConnectPosition=1, bRemeshAuto=False, dAvg=0.0012, dMin=0.0001, dMax=0.002)
        print(assemble_sretolid)
        ```
        
        """
        crNewPartCursor = "" if crNewPart == None else crNewPart.getPSJStr()
        crlAssemblePartsCursor = f"[{', '.join(crl.getPSJStr() for crl in crlAssembleParts)}]"
        crlNewFacesCursor = f"[{', '.join(crl.getPSJStr() for crl in crlNewFaces)}]"
        crlAssembleFacesCursor = f"[{', '.join(crl.getPSJStr() for crl in crlAssembleFaces)}]"
        message = "Exchange.AssembleSolidMesh({},{},{},{},{},{},{},{},{},{},{})".format(crNewPartCursor,crlAssemblePartsCursor,crlNewFacesCursor,crlAssembleFacesCursor,dTolerance,iConnectPosition,iRemeshLayer,bRemeshAuto,dAvg,dMin,dMax)
        return JPT_RUN_LINE(message)

