class Geometry:
    Bar = Geometry_Bar()

    BodyCut = Geometry_BodyCut()

    BreakEntity = Geometry_BreakEntity()

    DeleteEntity = Geometry_DeleteEntity()

    Edge = Geometry_Edge()

    Face = Geometry_Face()

    FindFeature = Geometry_FindFeature()

    MergeEntities = Geometry_MergeEntities()

    Part = Geometry_Part()

    ShowAdjacent = Geometry_ShowAdjacent()

    Transform = Geometry_Transform()

    def CADTrim(crlFaces=[],crlParts=[],dTrimSize=1.0,dTrimAngle=15.0):
        r"""
        ## Description
        
        This method reduces the number of facets (triangle patch shape) for CAD shape. This can be obtained by recursively finding and collapsing adjacent element edges that are at an angle less than a specified angle or at an element edge length less than a specified size.
        
        ## Syntax
        
        ```psj
        Geometry.CADTrim(crlFaces = [], crlParts = [], dTrimSize=1.0, dTrimAngle=15.0)
        ```
        
        Macro: [GeometryCADTrim](../../macro/geometry/GeometryCADTrim)
        
        Ribbon: <menuselection>Geometry &#187; CAD Trim</menuselection>
        
        ## Inputs
        
        ### `crlFaces`
        
        - A _List of Cursor_ specifying faces to be trimmed. Either _crlFaces_, or _crlParts_ must be specified.
        - The default value is [].
        
        ### `crlParts`
        
        - A _List of Cursor_ specifying parts to be trimmed. Either _crlFaces_, or _crlParts_ must be specified.
        - The default value is [].
        
        ### `dTrimSize`
        
        - A _Double_ specifying the maximum length of element edge.
        - The default value is 1.0.
        
        ### `dTrimAngle`
        
        - A _Double_ specifying the maximum angle in degrees between element edges.
        - The default value is 15.0.
        
        ## Return Code
        
        A _String_ of 1 if success, or 0 if fail.
        
        ## Sample Code
        
        ```psj
        Home.ImportCAD.Parasolid([JPT.GetProgramPath() + "SampleData\\bracket.x_t"],
            dAngleToleranceDegree=7.0, dScale=0.001)
        
        Geometry.CADTrim(crlFaces=[Face(149)], crlParts=[Part(1)], dTrimSize=20.0, dTrimAngle=16.0)
        ```
        
        """
        crlFacesCursor = f"[{', '.join(crl.getPSJStr() for crl in crlFaces)}]"
        crlPartsCursor = f"[{', '.join(crl.getPSJStr() for crl in crlParts)}]"
        message = "Geometry.CADTrim({},{},{},{})".format(crlFacesCursor,crlPartsCursor,dTrimSize,dTrimAngle)
        return JPT_RUN_LINE(message)

    def StitchEdge(crlMaster,crlSlave,dTolerance=0.3,bKeepSlave=True):
        r"""
        ## Description
        
        This method stitches any gap between free edges that are slightly apart.
        
        ## Syntax
        
        ```psj
        Geometry.StitchEdge(crlMaster, crlSlave, dTolerance=0.3, bKeepSlave=True)
        ```
        
        Macro: [StitchEdge](../../macro/geometry/StitchEdge)
        
        Ribbon: <menuselection>Geometry &#187; Stitch Edge</menuselection>
        
        ## Inputs
        
        ### `crlMaster`
        
        - A _List of Cursor_ specifying master edges will be retained after operation.
        - This is a required input.
        
        ### `crlSlave`
        
        - A _List of Cursor_ specifying slave edges to be stitched.
        - This is a required input.
        
        ### `dTolerance`
        
        - A _Double_ specifying the stitch tolerance. The free edges are at a distance less than or equal to the specified value will be stitched.
        - The default value is 0.3.
        
        ### `bKeepSlave`
        
        - A _Boolean_ specifying whether to keep slave nodes after the stitch operation.
        - The default value is _True_.
        
        ## Return Code
        
        A _String_ of 1 if success, or 0 if fail.
        
        ## Sample Code
        
        ```psj
        Geometry.Part.Cube()
        
        Geometry.Part.Cube(dlOrigin=[0.01, 0.01, 0.0], ilNodeCnt=[10, 10, 11], strName="Cube_2")
        
        Geometry.StitchEdge(crlMaster=[Edge(15)], crlSlave=[Edge(39))
        ```
        
        """
        crlMasterCursor = f"[{', '.join(crl.getPSJStr() for crl in crlMaster)}]"
        crlSlaveCursor = f"[{', '.join(crl.getPSJStr() for crl in crlSlave)}]"
        message = "Geometry.StitchEdge({},{},{},{})".format(crlMasterCursor,crlSlaveCursor,dTolerance,bKeepSlave)
        return JPT_RUN_LINE(message)

    def LogoRemoval(crlStartFaces,crlStopFaces,iLayers=5,bMergeFaces=False):
        r"""
        ## Description
        
        This method is used to automatically remove faces that configure logos or bolts.
        
        ## Syntax
        
        ```psj
        Geometry.LogoRemoval(crlStartFaces, crlStopFaces, iLayers=5, bMergeFaces=False)
        ```
        
        Macro: [LogoRemoval](../../macro/geometry/LogoRemoval)
        
        Ribbon: <menuselection>Geometry &#187; Logo Removal</menuselection>
        
        ## Inputs
        
        ### `crlStartFaces`
        
        - A _List of Cursor_ specifying the faces of the logo or bolt to be removed.
        - This is a required input.
        
        ### `crlStopFaces`
        
        - A _List of Cursor_ specifying the faces adjacent to the geometry to be removed.
        - This is a required input.
        
        ### `iLayers`
        
        - An _Integer_ specifying the number of layers in the depth direction of the target faces when removing bolts.
        - The default value is 5.
        
        ### `bMergeFaces`
        
        - A _Boolean_ specifying whether the adjacent faces should be merged after the removal operation.
        - The default value is _False_.
        
        ## Return Code
        
        A _String_ of 1 if success, or 0 if fail.
        
        ## Sample Code
        
        ```psj
        Geometry.Part.Cube()
        
        Geometry.Part.Cube(dlOrigin=[0.0045, 0.002, 0.0095], dlLength=[0.001, 0.006, 0.001])
        
        Geometry.Part.Cube(dlOrigin=[0.003, 0.001, 0.0095], dlLength=[0.004, 0.001, 0.001])
        
        Geometry.Part.Cube(dlOrigin=[0.003, 0.008, 0.0095], dlLength=[0.004, 0.001, 0.001])
        
        Assemble.BooleanEx([Part(2, 3, 4)])
        
        Geometry.MergeEntities.Faces(crlFaces=[Face(51, 52, 77, 78, 103, 104)])
        
        Assemble.BooleanEx([Part(1, 2)], iBooleanType=1)
        
        Geometry.LogoRemoval(crlStartFaces=[Face(51)], crlStopFaces=[Face(26)])
        ```
        
        """
        crlStartFacesCursor = f"[{', '.join(crl.getPSJStr() for crl in crlStartFaces)}]"
        crlStopFacesCursor = f"[{', '.join(crl.getPSJStr() for crl in crlStopFaces)}]"
        message = "Geometry.LogoRemoval({},{},{},{})".format(crlStartFacesCursor,crlStopFacesCursor,iLayers,bMergeFaces)
        return JPT_RUN_LINE(message)

