        Geometry.DeleteEntity.Face(crlFaces=[Face(24, 22, 25, 23, 21)])
        HexModeling.Linear(crlFaces=[Face(26)], dLength=0.01, vecSweepDirection=[0.0, 0.0, 1.0])
