        JPT.ViewFitToModel()
        
        MeshEdit.OneNode(
            crlNodes=[Node(45)],
            crlFaceFixed=[Face(21)], 
            bOffsetvector=True, dlOffset=[0.8, 0.0, 0.0], dOffset=0.0, 
            dDistStrong=2.0, dDistWeak=5.0)
        
        MeshEdit.OneNode(
            crlNodes=[Node(56)],
            crlFaceFixed=[Face(21)], 
            bOffsetvector=True, dlOffset=[-0.8, 0.0, 0.0], dOffset=0.0,
            dDistStrong=2.0, dDistWeak=5.0)
        
